        prefix[i+1] = prefix[i] + nums[i]
    }

    // Precompute left increasing and right increasing sequences
    leftInc := make([]int, n)
    rightInc := make([]int, n)

    leftInc[0] = 1
    for i := 1; i < n; i++ {
        if nums[i] > nums[i-1] {
            leftInc[i] = leftInc[i-1] + 1
        } else {
            leftInc[i] = 1
        }
    }

    rightInc[n-1] = 1
    for i := n - 2; i >= 0; i-- {
        if nums[i] < nums[i+1] {
            rightInc[i] = rightInc[i+1] + 1
        } else {
            rightInc[i] = 1
        }
    }

    for p := 1; p < n-2; p++ {
